import React from 'react';
import { useTheme } from '../context/ThemeContext';
import styled from 'styled-components';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { 
  faBullseye, 
  faEye, 
  faLightbulb, 
  faUsers, 
  faTrophy, 
  faSeedling, 
  faGlobeAmericas, 
  faRocket 
} from '@fortawesome/free-solid-svg-icons';

const MissionSection = styled.section`
  padding: 100px 10%;
  position: relative;
  overflow: hidden;
  background: ${({ theme }) => theme.gradientPrimary};
`;

const MissionContainer = styled.div`
  max-width: 1200px;
  margin: auto;
  position: relative;
  z-index: 2;
`;

const MissionHeader = styled.div`
  text-align: center;
  margin-bottom: 60px;
  &.values {
    margin-top: 60px;
  }
`;

const HeaderTitle = styled.h2`
  font-size: 3rem;
  color: ${({ theme }) => theme.primary};
  margin-bottom: 20px;
  position: relative;
  display: inline-block;
  text-transform: uppercase;
  letter-spacing: 1px;

  &::after {
    content: '';
    position: absolute;
    bottom: -10px;
    left: 50%;
    transform: translateX(-50%);
    width: 80px;
    height: 4px;
    background: ${({ theme }) => theme.gradientAccent};
    border-radius: 2px;
  }
`;

const MissionContent = styled.div`
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 40px;
  align-items: start;

  @media (max-width: 1024px) {
    grid-template-columns: 1fr;
  }
`;

const MissionCard = styled.div`
  background: ${({ theme }) => theme.cardBackground};
  backdrop-filter: blur(10px);
  border: 1px solid ${({ theme }) => theme.cardBorder};
  border-radius: 20px;
  padding: 40px;
  transition: all 0.4s ease;
  position: relative;
  overflow: hidden;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: ${({ theme }) => theme.gradientAccent};
    opacity: 0;
    transform: translateX(-100%);
    transition: transform 0.6s ease, opacity 0.4s ease;
  }

  &:hover {
    transform: translateY(-10px);
    box-shadow: ${({ theme }) => theme.shadow};
    border-color: ${({ theme }) => theme.primary};
  }

  &:hover::before {
    transform: translateX(100%);
    opacity: 0.1;
  }
`;

const CardTitle = styled.h3`
  font-size: 2rem;
  color: ${({ theme }) => theme.primary};
  margin-bottom: 20px;
  display: flex;
  align-items: center;
  gap: 15px;
  text-transform: uppercase;
  letter-spacing: 1px;

  svg {
    font-size: 2.5rem;
    filter: drop-shadow(0 0 10px ${({ theme }) => `${theme.primary}40`});
  }
`;

const CardText = styled.p`
  font-size: 1.1rem;
  color: ${({ theme }) => theme.text};
  line-height: 1.8;
  opacity: 0.9;
`;

const CoreValues = styled.div`
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 30px;
  margin-top: 40px;

  @media (max-width: 1024px) {
    grid-template-columns: repeat(2, 1fr);
  }

  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }
`;

const ValueItem = styled.div`
  background: ${({ theme }) => theme.cardBackground};
  backdrop-filter: blur(10px);
  border: 1px solid ${({ theme }) => theme.cardBorder};
  padding: 30px;
  border-radius: 15px;
  text-align: center;
  transition: all 0.4s ease;
  position: relative;
  overflow: hidden;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: ${({ theme }) => theme.gradientAccent};
    opacity: 0;
    transform: translateX(-100%);
    transition: transform 0.6s ease, opacity 0.4s ease;
  }

  &:hover {
    transform: translateY(-10px);
    box-shadow: ${({ theme }) => theme.shadow};
    border-color: ${({ theme }) => theme.primary};
  }

  &:hover::before {
    transform: translateX(100%);
    opacity: 0.1;
  }

  svg {
    font-size: 2.5rem;
    color: ${({ theme }) => theme.primary};
    margin-bottom: 20px;
    filter: drop-shadow(0 0 10px ${({ theme }) => `${theme.primary}40`});
  }
`;

const ValueTitle = styled.h4`
  color: ${({ theme }) => theme.primary};
  font-size: 1.3rem;
  margin-bottom: 10px;
  text-transform: uppercase;
  letter-spacing: 1px;
`;

const ValueText = styled.p`
  font-size: 0.9rem;
  color: ${({ theme }) => theme.text};
  margin: 0;
  opacity: 0.8;
`;

const Mission = () => {
  const { theme } = useTheme();

  const coreValues = [
    { icon: faLightbulb, title: 'Innovation', description: 'Pushing boundaries and creating new solutions' },
    { icon: faUsers, title: 'Teamwork', description: 'Collaborating to achieve common goals' },
    { icon: faTrophy, title: 'Excellence', description: 'Striving for the highest standards' },
    { icon: faSeedling, title: 'Growth Mindset', description: 'Continuous learning and development' },
    { icon: faGlobeAmericas, title: 'Community Impact', description: 'Making a positive difference together' },
    { icon: faRocket, title: 'Leadership', description: 'Inspiring and guiding others to success' }
  ];

  return (
    <MissionSection id="mission" theme={theme}>
      <MissionContainer>
        <MissionHeader>
          <HeaderTitle theme={theme} data-aos="fade-up" data-aos-duration="1000">
            Our Mission & Vision
          </HeaderTitle>
        </MissionHeader>

        <MissionContent>
          <MissionCard theme={theme} data-aos="fade-right" data-aos-duration="800">
            <CardTitle theme={theme}>
              <FontAwesomeIcon icon={faBullseye} />
              Our Mission
            </CardTitle>
            <CardText theme={theme}>
              At <strong>Optimus</strong>, we're dedicated to creating a dynamic space where innovation thrives. Our
              mission is to empower students through hands-on learning, collaborative projects, and real-world challenges.
              We believe in nurturing talent and providing the tools needed to turn ideas into impactful solutions.
            </CardText>
          </MissionCard>

          <MissionCard theme={theme} data-aos="fade-left" data-aos-duration="800">
            <CardTitle theme={theme}>
              <FontAwesomeIcon icon={faEye} />
              Our Vision
            </CardTitle>
            <CardText theme={theme}>
              We envision a future where every student has the opportunity to develop their technical skills and
              leadership abilities. Our goal is to build a community that not only learns together but also creates
              lasting impact through technology and innovation.
            </CardText>
          </MissionCard>
        </MissionContent>

        <MissionHeader className="values">
          <HeaderTitle theme={theme} data-aos="fade-up" data-aos-duration="1000">
            Core Values
          </HeaderTitle>
        </MissionHeader>

        <CoreValues>
          {coreValues.map((value, index) => (
            <ValueItem 
              key={index} 
              theme={theme}
              data-aos="zoom-in" 
              data-aos-delay={100 * (index + 1)}
            >
              <FontAwesomeIcon icon={value.icon} />
              <ValueTitle theme={theme}>{value.title}</ValueTitle>
              <ValueText theme={theme}>{value.description}</ValueText>
            </ValueItem>
          ))}
        </CoreValues>
      </MissionContainer>
    </MissionSection>
  );
};

export default Mission;
